import{_ as a,o as l,c as s,a9 as e}from"./chunks/framework.STMWz9Nm.js";const c=JSON.parse('{"title":"宏系统入门","description":"","frontmatter":{},"headers":[],"relativePath":"语言/Rust/01-Rust语言基础与核心机制/12-宏系统入门.md","filePath":"语言/Rust/01-Rust语言基础与核心机制/12-宏系统入门.md","lastUpdated":1777177198000}'),h={name:"语言/Rust/01-Rust语言基础与核心机制/12-宏系统入门.md"};function t(r,i,n,p,d,k){return l(),s("div",null,[...i[0]||(i[0]=[e(`<h1 id="宏系统入门" tabindex="-1">宏系统入门 <a class="header-anchor" href="#宏系统入门" aria-label="Permalink to “宏系统入门”">​</a></h1><h2 id="_1-这是什么" tabindex="-1">1. 这是什么 <a class="header-anchor" href="#_1-这是什么" aria-label="Permalink to “1. 这是什么”">​</a></h2><p>Rust 的宏，是一类<strong>在编译阶段参与代码生成和展开</strong>的机制。<br> 它不是普通函数调用，而更像：</p><ul><li>先根据规则改写代码</li><li>再把改写后的结果交给编译器继续处理</li></ul><p>你平时很可能已经见过它：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">println!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;hello&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">);</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vec!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">];</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">format!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;{}&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, name);</span></span></code></pre></div><p>这些带 <code>!</code> 的调用，很多都是宏。</p><p>一句话理解：</p><ul><li>函数是在运行时处理值</li><li>宏是在编译时处理代码结构</li></ul><h2 id="_2-为什么重要" tabindex="-1">2. 为什么重要 <a class="header-anchor" href="#_2-为什么重要" aria-label="Permalink to “2. 为什么重要”">​</a></h2><p>很多人刚学 Rust 时会把宏当成“高级语法糖”，但它其实很重要，因为 Rust 很多日常体验都依赖它：</p><ul><li>打印与格式化</li><li>集合字面量风格的便捷写法</li><li>派生能力（<code>#[derive(...)]</code>）</li><li>某些 DSL 风格接口</li><li>大量样板代码的自动生成</li></ul><p>宏重要，不只是因为它“能少写代码”，更因为它能：</p><ul><li>提高表达力</li><li>把重复模式抽象出来</li><li>在不牺牲零成本特性的前提下增强语言可用性</li></ul><h2 id="_3-先建立直觉" tabindex="-1">3. 先建立直觉 <a class="header-anchor" href="#_3-先建立直觉" aria-label="Permalink to “3. 先建立直觉”">​</a></h2><p>先把宏和函数分开想：</p><h3 id="函数处理的是值" tabindex="-1">函数处理的是值 <a class="header-anchor" href="#函数处理的是值" aria-label="Permalink to “函数处理的是值”">​</a></h3><p>比如：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">add</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)</span></span></code></pre></div><p>这表示：</p><ul><li>先有两个值</li><li>再把它们传给函数处理</li></ul><h3 id="宏处理的是代码形状" tabindex="-1">宏处理的是代码形状 <a class="header-anchor" href="#宏处理的是代码形状" aria-label="Permalink to “宏处理的是代码形状”">​</a></h3><p>比如：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">vec!</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">3</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span></code></pre></div><p>它更像是在说：</p><ul><li>编译器先看到一段符合某种模式的代码</li><li>再把它展开成更底层的 Rust 代码</li></ul><p>所以宏不是“普通函数的特殊写法”，而是“在编译前介入代码结构”。</p><h2 id="_4-核心内容" tabindex="-1">4. 核心内容 <a class="header-anchor" href="#_4-核心内容" aria-label="Permalink to “4. 核心内容”">​</a></h2><h3 id="_4-1-为什么-rust-需要宏" tabindex="-1">4.1 为什么 Rust 需要宏 <a class="header-anchor" href="#_4-1-为什么-rust-需要宏" aria-label="Permalink to “4.1 为什么 Rust 需要宏”">​</a></h3><p>Rust 很强调：</p><ul><li>类型安全</li><li>零成本抽象</li><li>编译期检查</li></ul><p>但如果完全只靠函数和泛型，有些表达会很别扭。<br> 比如：</p><ul><li>可变参数风格打印</li><li>类似字面量的便捷构造</li><li>批量生成重复实现</li></ul><p>这时宏就能补上“编译期代码生成”这块能力。</p><h3 id="_4-2-最常见的是声明式宏" tabindex="-1">4.2 最常见的是声明式宏 <a class="header-anchor" href="#_4-2-最常见的是声明式宏" aria-label="Permalink to “4.2 最常见的是声明式宏”">​</a></h3><p>初学阶段，你最先接触的一般是声明式宏（<code>macro_rules!</code>）。<br> 它的直觉可以理解成：</p><ul><li>写一组模式</li><li>告诉编译器“匹配到这种代码时，就展开成那种代码”</li></ul><p>你暂时不用一上来就背完整语法，只要知道：</p><ul><li>它是在做模式匹配式的代码改写</li><li>很多常见宏都属于这一类</li></ul><p>这也是为什么学过 <code>match</code> 后再看宏，理解会更顺。</p><h3 id="_4-3-println-为什么是宏-不是函数" tabindex="-1">4.3 <code>println!</code> 为什么是宏，不是函数 <a class="header-anchor" href="#_4-3-println-为什么是宏-不是函数" aria-label="Permalink to “4.3 println! 为什么是宏，不是函数”">​</a></h3><p>这是一个很好的入门问题。</p><p>因为 <code>println!</code> 需要支持：</p><ul><li>不同数量的参数</li><li>格式化模板</li><li>编译期对格式占位进行检查</li></ul><p>如果只靠普通函数，体验和能力都会受限。<br> 宏则可以在编译期把这些结构整理好，再生成合适代码。</p><p>所以像 <code>println!</code>、<code>format!</code>、<code>vec!</code> 这些典型工具，做成宏是很自然的选择。</p><h3 id="_4-4-宏和-少写代码-不是一回事" tabindex="-1">4.4 宏和“少写代码”不是一回事 <a class="header-anchor" href="#_4-4-宏和-少写代码-不是一回事" aria-label="Permalink to “4.4 宏和“少写代码”不是一回事”">​</a></h3><p>很多人一提宏就只想到“偷懒”。<br> 其实更准确地说，宏是在抽象<strong>重复的代码结构模式</strong>。</p><p>比如有些重复，不是值的重复，而是代码骨架的重复：</p><ul><li>一组字段对应一组实现</li><li>一组规则对应一组匹配分支</li><li>一组声明对应一组样板代码</li></ul><p>函数擅长抽象值层面的重复。<br> 宏擅长抽象代码形状层面的重复。</p><h3 id="_4-5-derive-也属于宏世界的一部分" tabindex="-1">4.5 <code>#[derive(...)]</code> 也属于宏世界的一部分 <a class="header-anchor" href="#_4-5-derive-也属于宏世界的一部分" aria-label="Permalink to “4.5 #[derive(...)] 也属于宏世界的一部分”">​</a></h3><p>很多人第一次真正大量使用 Rust 宏，往往不是 <code>macro_rules!</code>，而是：</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">#[derive(</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Debug</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">Clone</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)]</span></span></code></pre></div><p>这类 derive 本质上也是让编译器根据你的类型定义，自动生成一部分代码。<br> 它让 Rust 在保持显式性的同时，不至于被样板代码淹没。</p><p>所以学宏时要建立一个更完整的图景：</p><ul><li>宏不只是 <code>println!</code></li><li>属性宏、derive 宏也都属于宏系统的重要组成部分</li></ul><h3 id="_4-6-宏的价值-增强语言表达力" tabindex="-1">4.6 宏的价值：增强语言表达力 <a class="header-anchor" href="#_4-6-宏的价值-增强语言表达力" aria-label="Permalink to “4.6 宏的价值：增强语言表达力”">​</a></h3><p>Rust 之所以大量使用宏，一个重要原因是它不想把所有便利都硬塞进核心语法。<br> 宏提供了一种折中方式：</p><ul><li>语言核心保持相对克制</li><li>但通过宏扩展出很强的表达能力</li></ul><p>所以宏在 Rust 里地位很高，不是边缘功能。</p><h3 id="_4-7-为什么宏也容易让人害怕" tabindex="-1">4.7 为什么宏也容易让人害怕 <a class="header-anchor" href="#_4-7-为什么宏也容易让人害怕" aria-label="Permalink to “4.7 为什么宏也容易让人害怕”">​</a></h3><p>宏强大，但也会带来问题：</p><ul><li>报错有时更难读</li><li>展开后的真实代码不直观</li><li>写宏的心智负担比写函数高</li><li>滥用后会让代码可读性下降</li></ul><p>所以宏的常见原则不是“能用就用”，而是：</p><ul><li>优先考虑函数、trait、泛型能不能解决</li><li>只有在“代码结构抽象”层面确实需要时，再考虑宏</li></ul><h3 id="_4-8-宏不是替代普通抽象-而是补充" tabindex="-1">4.8 宏不是替代普通抽象，而是补充 <a class="header-anchor" href="#_4-8-宏不是替代普通抽象-而是补充" aria-label="Permalink to “4.8 宏不是替代普通抽象，而是补充”">​</a></h3><p>最容易建立的健康直觉是：</p><ul><li>能用函数解决，就先用函数</li><li>能用 trait / 泛型解决，就先用 trait / 泛型</li><li>只有当问题是“代码模式重复”而不是“值处理重复”时，再考虑宏</li></ul><p>也就是说，宏不是为了取代普通抽象，而是在普通抽象不够表达时补位。</p><h2 id="_5-常见误区" tabindex="-1">5. 常见误区 <a class="header-anchor" href="#_5-常见误区" aria-label="Permalink to “5. 常见误区”">​</a></h2><h3 id="_5-1-误区一-带-的都是函数快捷写法" tabindex="-1">5.1 误区一：带 <code>!</code> 的都是函数快捷写法 <a class="header-anchor" href="#_5-1-误区一-带-的都是函数快捷写法" aria-label="Permalink to “5.1 误区一：带 ! 的都是函数快捷写法”">​</a></h3><p>不是。<br> 带 <code>!</code> 往往是在提醒你：这不是普通函数调用，而是宏展开。</p><h3 id="_5-2-误区二-宏就是为了少写几行代码" tabindex="-1">5.2 误区二：宏就是为了少写几行代码 <a class="header-anchor" href="#_5-2-误区二-宏就是为了少写几行代码" aria-label="Permalink to “5.2 误区二：宏就是为了少写几行代码”">​</a></h3><p>不完整。<br> 宏真正解决的是“代码结构级别的重复与表达”。</p><h3 id="_5-3-误区三-宏越多-代码越高级" tabindex="-1">5.3 误区三：宏越多，代码越高级 <a class="header-anchor" href="#_5-3-误区三-宏越多-代码越高级" aria-label="Permalink to “5.3 误区三：宏越多，代码越高级”">​</a></h3><p>恰恰相反。<br> 宏应该在真正必要时使用。过度宏化会让代码更难理解、更难调试。</p><h3 id="_5-4-误区四-会用-println-就等于理解宏系统" tabindex="-1">5.4 误区四：会用 <code>println!</code> 就等于理解宏系统 <a class="header-anchor" href="#_5-4-误区四-会用-println-就等于理解宏系统" aria-label="Permalink to “5.4 误区四：会用 println! 就等于理解宏系统”">​</a></h3><p>那只是开始。<br> 真正理解宏，要知道它和函数、trait、泛型在抽象层次上的差异。</p><h2 id="_6-一个更实用的判断思路" tabindex="-1">6. 一个更实用的判断思路 <a class="header-anchor" href="#_6-一个更实用的判断思路" aria-label="Permalink to “6. 一个更实用的判断思路”">​</a></h2><p>当你在 Rust 里想“这里要不要上宏”时，可以先问：</p><ol><li>这是不是值处理问题，而不是代码结构问题</li><li>普通函数能不能解决</li><li>trait / 泛型能不能解决</li><li>当前重复的是逻辑，还是代码骨架</li><li>用宏后，代码可读性会变更好还是更差</li></ol><p>如果答案是：</p><ul><li>普通抽象不太适合</li><li>重复主要发生在代码结构层面</li><li>宏能显著提升表达力</li></ul><p>那再考虑宏，通常更稳。</p><h2 id="_7-学习建议" tabindex="-1">7. 学习建议 <a class="header-anchor" href="#_7-学习建议" aria-label="Permalink to “7. 学习建议”">​</a></h2><p>建议按这个顺序学习宏系统：</p><ol><li>先理解“宏是编译期代码展开，不是运行时函数”</li><li>先会使用常见宏：<code>println!</code>、<code>format!</code>、<code>vec!</code></li><li>再理解 <code>macro_rules!</code> 的模式匹配思路</li><li>再认识 <code>derive</code>、属性宏在工程中的角色</li><li>最后再深入过程宏和更复杂的宏设计</li></ol><p>这样会更容易从“会用”走向“能判断什么时候该用”。</p><h2 id="_8-自测标准" tabindex="-1">8. 自测标准 <a class="header-anchor" href="#_8-自测标准" aria-label="Permalink to “8. 自测标准”">​</a></h2><ul><li>能解释宏和函数最本质的区别</li><li>能说清为什么 <code>println!</code>、<code>vec!</code> 这类能力更适合做成宏</li><li>能理解宏更擅长抽象代码结构，而不是值处理逻辑</li><li>能知道 <code>derive</code> 也属于宏系统的重要部分</li><li>能判断宏不该替代函数、trait、泛型这些普通抽象</li><li>能建立“宏很强，但要克制使用”的基本工程判断</li></ul>`,91)])])}const u=a(h,[["render",t]]);export{c as __pageData,u as default};
